int array_max(int n, int *a)
/*@ With l
    Require
      1 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == max_list_nonempty(l) &&
      IntArray::full(a, n, l)
*/
{
